import { choose, weightedRandom } from '../../functions/dice.functions.js';
import { capitalize } from '../../functions/utils.functions.js';
import { humanNames, villageNamesSv, villageNamesEn } from './data/name.data.js';
export const kinTypes = ['Human', 'Elf', 'Dwarf', 'Ogre', 'Orc', 'Wolfkin', 'Saurian', 'Whiner', 'HalflingAndGoblin'];
export const getKinTypes = () => [...kinTypes];

const getRandomName = (g, lang, nameList, chooseFunc = choose) => {
  const {
    type,
    firstName
  } = getNameTypeAndFirstName(g, nameList);

  switch (type) {
    case 'FamilyName':
      {
        if (!nameList.family || nameList.family.length === 0) {
          return [firstName];
        }

        return [firstName, chooseFunc(nameList.family)];
      }

    case 'NickName':
      {
        if (!nameList.nickName || nameList.nickName.length === 0) {
          return [firstName];
        }

        return [firstName, 'THE', chooseFunc(nameList.nickName)];
      }

    case 'HomeName':
      return [firstName, 'OF', formatVillageName(getVillagePrefixAndSuffix(lang, chooseFunc), lang)];

    case 'FirstName':
    default:
      return [firstName];
  }
};

export const getRandomAilanderName = (g, lang, nameList = humanNames.Ailander, chooseFunc = choose) => {
  return getRandomName(g, lang, nameList, chooseFunc);
};
export const getRandomAlderlanderName = (g, lang, nameList = humanNames.Ailander, chooseFunc = choose) => {
  return getRandomName(g, lang, nameList, chooseFunc);
};
export const getRandomAsleneName = (g, lang, nameList = humanNames.Aslene, chooseFunc = choose) => {
  return getRandomName(g, lang, nameList, chooseFunc);
};
export const getNameTypeAndFirstName = (g, nl) => {
  return {
    type: weightedRandom(nl[g].probabilites).type,
    firstName: choose(nl[g].rawNames)
  };
};
export const getVillageNameList = lang => {
  switch (lang) {
    case 'sv':
      return villageNamesSv;

    case 'en':
      return villageNamesEn;

    default:
      {
        const exhaustiveCheck = lang;
        throw new Error(exhaustiveCheck);
      }
  }
};
export const getVillagePrefixAndSuffix = (lang, choiceFunc = choose) => {
  const {
    prefix,
    suffix
  } = getVillageNameList(lang);
  return [choiceFunc(prefix), choiceFunc(suffix)];
};
export const formatVillageName = (prefixAndSuffix, lang) => {
  const separator = lang === 'en' ? ' ' : '';
  return prefixAndSuffix.map(fix => lang === 'en' ? capitalize(fix) : fix).join(separator);
};